package com.grl.component.asg;

import org.semanticweb.owlapi.model.IRI;

public interface OntologyConstants {
  // IRI Namespaces
  final String GRL_NS = "https://www.graphresearchlabs.com/";
  final String GRL_BASE_NS = GRL_NS + "base/";
  final String GRL_ANNOTATION_NS = "http://ontologies.semanticarts.com/o/grlAnnotationProperties/";
  final String RDFS_NS = "http://www.w3.org/2000/01/rdf-schema#";
  final String SKOS_NS = "http://www.w3.org/2004/02/skos/core#";
  final String PROV_NS = "http://www.w3.org/ns/prov#";

  // Well known Annotation property shortform iris, note the value text case is variable due to ontology usage, always
  // camel for constant names
  final String apiSchema = "apiSchema";
  final String apiDescription = "apiDescription";
  final String apiSummary = "apisummary";
  final String apiLabel = "apiLabel";
  final String apiDisplayLabel = "apiDisplayLabel";
  final String apiTag = "apitag";
  final String apiVersion = "apiversion";
  final String security = "security";
  final String apiID = "apiID";

  // Well known classes
  final String apiRoot = "APIRoot";

  // Well known properties
  final String hasAPI = "hasAPI";
  final String hasResourceSchema = "hasResourceSchema";


  // Wellknown IRIs
  final IRI PROV_DEFINITION = IRI.create(PROV_NS, "definition");
  final IRI SKOS_DEFINITION = IRI.create(SKOS_NS, "definition");
  final IRI SKOS_PREFLABEL = IRI.create(SKOS_NS, "prefLabel");
  final IRI SKOS_EXAMPLE = IRI.create(SKOS_NS, "example");
  final IRI RDFS_COMMENT = IRI.create(RDFS_NS, "comment");
  final IRI API_ID_IRI = IRI.create(GRL_ANNOTATION_NS, apiID);
}

