    13→
    14→/**
    15→ * Test that a simple API (employer) gets generated correctly.
    16→ *
    17→ * <ul>
    18→ *  <li>Api has title, description, termsOfService, contact, version, x-grl-api-label, x-grl-graph-namespace in info.</li>
    19→ *  <li>Api has Employee and Employer resources.</li>
    20→ *  <li>each resource has single and collection endpoints.</li>
    21→ *  <li>each endpoint has standard methods.</li>
    22→ *  <li>each method has standard parameters and responses.</li>
    23→ *  <li>resources have basic properties only.</li>
    24→ * </ul>
    25→ */
    26→public class SimpleApiIT {
    27→
    28→  ReadContext employeeSpec = TestUtil.getGeneratedSpec(
    29→      TestUtil.asFilePath(SimpleApiIT.class, "config_employee.yaml"));
    30→
    31→  @Test
    32→  public void withEmployeeInfoIsCorrect() {
    33→    assertEquals("EmploymentAPIV1.0.1", employeeSpec.read("$.info.title"));
    34→    assertEquals("Minimal Test API", employeeSpec.read("$.info.description"));
    35→    assertEquals("some terms", employeeSpec.read("$.info.termsOfService"));
    36→    assertEquals("Test Contact", employeeSpec.read("$.info.contact.name"));
    37→    assertEquals("http://test/url", employeeSpec.read("$.info.contact.url"));
    38→    assertEquals("support@graphresearchlabs.com", employeeSpec.read("$.info.contact.email"));
    39→    assertEquals("1.0.0", employeeSpec.read("$.info.version"));
    40→    assertEquals("EmploymentAPIV1.0.1", employeeSpec.read("$.info.x-grl-api-label"));
    41→    assertEquals("https://www.graphresearchlabs.com/employment/",
    42→        employeeSpec.read("$.info.x-grl-graph-namespace"));
    43→  }
    44→
    45→  @Test
    46→  public void withEmployeeTagsCorrect() {
    47→    assertEquals(2, (int) employeeSpec.read("$.tags.length()"));
    48→    assertEquals("Employee", employeeSpec.read("$.tags[0].name"));
    49→    assertEquals("A person who is employed by another person or organizational entity.",
    50→        employeeSpec.read("$.tags[0].description"));
    51→    assertEquals("Employer", employeeSpec.read("$.tags[1].name"));
    52→  }
    53→
    54→  @Test
    55→  public void withEmployeePathsCorrect() {
    56→    assertEquals(4, (int) employeeSpec.read("$.paths.length()"));
    57→    assertEquals(
