    assertEquals(1, spec.read("$.components.schemas.ValueRestrictionsTest.properties.someValuesString.minItems", Integer.class));

    List<String> required = spec.read("$.components.schemas.ValueRestrictionsTest.required", List.class);
    assertTrue(required.contains("someValuesString"), "someValuesString should be required");
