  @Test
  void apiIdPropertyExists() {
    assertNotNull(spec.read("$.components.schemas.ValueRestrictionsTest.properties.apiID"));
    assertEquals("string", spec.read("$.components.schemas.ValueRestrictionsTest.properties.apiID.type"));
  }

  @Test
  void schemaHasCorrectStructure() {
    assertEquals("object", spec.read("$.components.schemas.ValueRestrictionsTest.type"));
    assertEquals("Value Restrictions Test", spec.read("$.components.schemas.ValueRestrictionsTest.title"));
  }
}

