package regression.features.restrictions;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.TestUtil;
import com.jayway.jsonpath.ReadContext;
import java.util.List;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

/**
 * Integration tests for cardinality restrictions.
 * Tests minCardinality, maxCardinality, and exactCardinality restrictions
 * and their mapping to OpenAPI minItems/maxItems and required fields.
 */
public class CardinalityRestrictionsIT {

  private static ReadContext spec;

  @BeforeAll
  static void setup() {
    spec = TestUtil.getGeneratedSpec(
        TestUtil.asFilePath(CardinalityRestrictionsIT.class, "/regression/configs/config_cardinality.yaml"));
  }

  @Test
  void minCardinalityOneCreatesMinItemsAndRequired() {
    // minCardinality(1) should create minItems: 1 and add to required
    assertEquals(1, spec.read("$.components.schemas.CardinalityTest.properties.minCardOne.minItems", Integer.class));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("minCardOne"), "minCardOne should be required");
  }

  @Test
  void minCardinalityTwoCreatesArrayWithMinItems() {
    // minCardinality(2) should create array with minItems: 2
    assertEquals("array", spec.read("$.components.schemas.CardinalityTest.properties.minCardTwo.type"));
    assertEquals(2, spec.read("$.components.schemas.CardinalityTest.properties.minCardTwo.minItems", Integer.class));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("minCardTwo"), "minCardTwo should be required");
  }

  @Test
  void maxCardinalityOneCreatesMaxItems() {
    // maxCardinality(1) should create maxItems: 1
    assertEquals(1, spec.read("$.components.schemas.CardinalityTest.properties.maxCardOne.maxItems", Integer.class));
    // maxCardinality alone should NOT make it required
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    // maxCardOne should not be required (only max, no min)
  }

  @Test
  void maxCardinalityThreeCreatesMaxItems() {
    // maxCardinality(3) should create maxItems: 3
    assertEquals(3, spec.read("$.components.schemas.CardinalityTest.properties.maxCardThree.maxItems", Integer.class));
  }

  @Test
  void exactCardinalityOneCreatesBothMinAndMax() {
    // exactCardinality(1) should create both minItems: 1 and maxItems: 1
    assertEquals(1, spec.read("$.components.schemas.CardinalityTest.properties.exactCardOne.minItems", Integer.class));
    assertEquals(1, spec.read("$.components.schemas.CardinalityTest.properties.exactCardOne.maxItems", Integer.class));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("exactCardOne"), "exactCardOne should be required");
  }

  @Test
  void exactCardinalityTwoCreatesArrayWithBothMinAndMax() {
    // exactCardinality(2) should create array with minItems: 2 and maxItems: 2
    assertEquals("array", spec.read("$.components.schemas.CardinalityTest.properties.exactCardTwo.type"));
    assertEquals(2, spec.read("$.components.schemas.CardinalityTest.properties.exactCardTwo.minItems", Integer.class));
    assertEquals(2, spec.read("$.components.schemas.CardinalityTest.properties.exactCardTwo.maxItems", Integer.class));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("exactCardTwo"), "exactCardTwo should be required");
  }

  @Test
  void apiIdPropertyExists() {
    // Every resource should have apiID
    assertNotNull(spec.read("$.components.schemas.CardinalityTest.properties.apiID"));
    assertEquals("string", spec.read("$.components.schemas.CardinalityTest.properties.apiID.type"));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("apiID"), "apiID should be required");
  }

  @Test
  void schemaHasCorrectStructure() {
    assertEquals("object", spec.read("$.components.schemas.CardinalityTest.type"));
    assertEquals("Cardinality Test", spec.read("$.components.schemas.CardinalityTest.title"));
    assertEquals(false, spec.read("$.components.schemas.CardinalityTest.additionalProperties", Boolean.class));
  }
}

