/**
 * Integration tests for cardinality restrictions.
 * Tests minCardinality, maxCardinality, and exactCardinality restrictions
 * and their mapping to OpenAPI types and required fields.
 *
 * Note: Currently ASG generates required fields based on cardinality but does not
 * populate minItems/maxItems from qualified cardinality restrictions.
 */
public class CardinalityRestrictionsIT {

  private static ReadContext spec;

  @BeforeAll
  static void setup() {
    spec = TestUtil.getGeneratedSpec(
        TestUtil.asFilePath(CardinalityRestrictionsIT.class, "/regression/configs/config_cardinality.yaml"));
  }

  @Test
  void minCardinalityOneIsRequired() {
    // minCardinality(1) should add to required
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("minCardOne"), "minCardOne should be required");
    // Singular cardinality generates string type (not array)
    assertEquals("string", spec.read("$.components.schemas.CardinalityTest.properties.minCardOne.type"));
  }

  @Test
  void minCardinalityTwoCreatesArrayAndIsRequired() {
    // minCardinality(2) should create array and be required
    assertEquals("array", spec.read("$.components.schemas.CardinalityTest.properties.minCardTwo.type"));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("minCardTwo"), "minCardTwo should be required");
  }

  @Test
  void maxCardinalityOneIsNotRequired() {
    // maxCardinality(1) alone should NOT make it required
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertFalse(required.contains("maxCardOne"), "maxCardOne should not be required");
    // max=1 generates string type (not array)
    assertEquals("string", spec.read("$.components.schemas.CardinalityTest.properties.maxCardOne.type"));
  }

  @Test
  void maxCardinalityThreeCreatesArray() {
    // maxCardinality(3) should create array (cardinality > 1 implies array)
    assertEquals("array", spec.read("$.components.schemas.CardinalityTest.properties.maxCardThree.type"));
  }

  @Test
  void exactCardinalityOneIsRequiredAndSingular() {
    // exactCardinality(1) should be required and singular (not array)
    assertEquals("string", spec.read("$.components.schemas.CardinalityTest.properties.exactCardOne.type"));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("exactCardOne"), "exactCardOne should be required");
  }

  @Test
  void exactCardinalityTwoCreatesArrayAndIsRequired() {
    // exactCardinality(2) should create array and be required
    assertEquals("array", spec.read("$.components.schemas.CardinalityTest.properties.exactCardTwo.type"));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("exactCardTwo"), "exactCardTwo should be required");
  }

  @Test
  void apiIdPropertyExists() {
    // Every resource should have apiID
    assertNotNull(spec.read("$.components.schemas.CardinalityTest.properties.apiID"));
    assertEquals("string", spec.read("$.components.schemas.CardinalityTest.properties.apiID.type"));
    List<String> required = spec.read("$.components.schemas.CardinalityTest.required", List.class);
    assertTrue(required.contains("apiID"), "apiID should be required");
  }

  @Test
  void schemaHasCorrectStructure() {
