  }

  @Test
  void dateMapsToStringWithDateFormat() {
    assertEquals("string", spec.read(SCHEMA_PATH + ".dateProp.type"));
    // Note: date format may vary based on implementation
  }

  @Test
  void timeMapsToString() {
    assertEquals("string", spec.read(SCHEMA_PATH + ".timeProp.type"));
  }

  @Test
  void anyURIMapsToStringWithUriFormat() {
