package regression.features.restrictions;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.TestUtil;
import com.jayway.jsonpath.ReadContext;
import java.util.List;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

/**
 * Integration tests for value restrictions.
 * Tests someValuesFrom, allValuesFrom, hasValue, and dataOneOf restrictions.
 */
public class ValueRestrictionsIT {

  private static ReadContext spec;

  @BeforeAll
  static void setup() {
    spec = TestUtil.getGeneratedSpec(
        TestUtil.asFilePath(ValueRestrictionsIT.class, "/regression/configs/config_value_restrictions.yaml"));
  }

  @Test
  void someValuesFromCreatesArrayWithMinItemsOne() {
    // someValuesFrom should create array with minItems: 1 and be required
    assertEquals("array", spec.read("$.components.schemas.ValueRestrictionsTest.properties.someValuesString.type"));
    assertEquals(1, spec.read("$.components.schemas.ValueRestrictionsTest.properties.someValuesString.minItems", Integer.class));

    List<String> required = spec.read("$.components.schemas.ValueRestrictionsTest.required", List.class);
    assertTrue(required.contains("someValuesString"), "someValuesString should be required");
  }

  @Test
  void allValuesFromCreatesTypeConstraintOnly() {
    // allValuesFrom should create type constraint but NOT be required
    // and should NOT have minItems (no cardinality implied)
    assertNotNull(spec.read("$.components.schemas.ValueRestrictionsTest.properties.allValuesString"));

    // allValuesFrom alone doesn't make it required
    List<String> required = spec.read("$.components.schemas.ValueRestrictionsTest.required", List.class);
    // allValuesString should NOT be in required (unless combined with other restrictions)
  }

  @Test
  void hasValueCreatesDefault() {
    // hasValue should create a default value
    assertEquals("DefaultValue", spec.read("$.components.schemas.ValueRestrictionsTest.properties.hasValueDefault.default"));
  }

  @Test
  void dataOneOfCreatesEnum() {
    // dataOneOf should create an enum
    List<String> enumValues = spec.read("$.components.schemas.ValueRestrictionsTest.properties.dataOneOfEnum.items.enum", List.class);
    assertNotNull(enumValues, "dataOneOfEnum should have enum values");
    assertTrue(enumValues.contains("low"), "Enum should contain 'low'");
    assertTrue(enumValues.contains("medium"), "Enum should contain 'medium'");
    assertTrue(enumValues.contains("high"), "Enum should contain 'high'");
  }

  @Test
  void apiIdPropertyExists() {
    assertNotNull(spec.read("$.components.schemas.ValueRestrictionsTest.properties.apiID"));
    assertEquals("string", spec.read("$.components.schemas.ValueRestrictionsTest.properties.apiID.type"));
  }

  @Test
  void schemaHasCorrectStructure() {
    assertEquals("object", spec.read("$.components.schemas.ValueRestrictionsTest.type"));
    assertEquals("Value Restrictions Test", spec.read("$.components.schemas.ValueRestrictionsTest.title"));
  }
}

