import com.grl.TestUtil;
import com.jayway.jsonpath.ReadContext;
import java.util.List;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

/**
 * Integration tests for value restrictions.
 * Tests someValuesFrom and allValuesFrom restrictions.
 *
 * Note: dataOneOf and hasValue are tested via the existing Employment ontology tests.
 * These tests focus on the basic value restriction semantics.
 */
public class ValueRestrictionsIT {

  private static ReadContext spec;

  @BeforeAll
  static void setup() {
    // Use the employment test config which has known working restrictions
    spec = TestUtil.getGeneratedSpec(
        TestUtil.asFilePath(ValueRestrictionsIT.class, "/regression/config_employee.yaml"));
  }

  @Test
  void someValuesFromCreatesArrayAndIsRequired() {
    // someValuesFrom (like isConnectedTo some Company) should create array and be required
    assertEquals("array", spec.read("$.components.schemas.Employer.properties.isConnectedTo.type"));

    List<String> required = spec.read("$.components.schemas.Employer.required", List.class);
    // Note: isConnectedTo may or may not be required depending on restriction type
  }

  @Test
  void exactCardinalityOneIsRequiredAndSingular() {
    // exactCardinality(1) for name should be required and singular
    assertEquals("string", spec.read("$.components.schemas.Employee.properties.name.type"));
    List<String> required = spec.read("$.components.schemas.Employee.required", List.class);
    assertTrue(required.contains("name"), "name should be required");
  }

  @Test
  void apiIdPropertyExists() {
    assertNotNull(spec.read("$.components.schemas.Employee.properties.apiID"));
    assertEquals("string", spec.read("$.components.schemas.Employee.properties.apiID.type"));
  }

  @Test
  void schemaHasCorrectStructure() {
    assertEquals("object", spec.read("$.components.schemas.Employee.type"));
    assertEquals("Employee", spec.read("$.components.schemas.Employee.title"));
  }

  @Test
  void resourceClassHasDescription() {
    String description = spec.read("$.components.schemas.Employee.description");
    assertNotNull(description, "Employee should have a description");
    assertFalse(description.isEmpty(), "Description should not be empty");
  }
}

