  private static String getDataType(String key) {
    return dataTypes.get(key);
  }

  private static final String STRING_TYPE = "string";
  private static final String NUMBER_TYPE = "number";
  private static final String INTEGER_TYPE = "integer";
  private static final String BOOLEAN_TYPE = "boolean";
  private static final String DATETIME_TYPE = "dateTime";

  private final String name;
  final String label;
  final String description;
  final Object exampleValue;
  private final List<String> type;
  private final Boolean array;
  private Boolean isRequired;
  private final Set<RestrictionInfo> restrictions;
  private final List<String> valuesFromDataRestrictions_ranges;

  public Boolean isRequired() {
    return isRequired;
  }

  /**
   * Apply an example object the given schema. If we have an example object provided on construction
   * we use it, otherwise apply a heuristic based on the type/format of the schema to get an
   * appropriate example.
   *
   * @param parentSchema if this is composed (i.e. an array) the example will be applied to the
   *                     outer schema with a note that it is an array
   * @param <T>          schema to apply example to
   * @return schema with example
   */
  private <T extends Schema<?>> T withExample(T parentSchema) {
    boolean isArray = parentSchema.getType() != null && parentSchema.getType().equals("array");
    Schema<?> schema = isArray ? parentSchema.getItems() : parentSchema;

    // Get schema type, handling null
    String schemaType = schema.getType();
    if (schemaType == null) {
      return parentSchema;
    }

    Optional.ofNullable(exampleValue).or(() -> Optional.ofNullable(switch (schemaType) {
      case "string" -> {
        String format = schema.getFormat();
        yield format == null ? name + " string value" : switch (format) {
          case "uri" -> "http://www.example.com";
          case "date" -> "2025-01-15";
          case "date-time" -> "2025-01-15T14:55:58+00:00";
          case "time" -> "14:55:58+00:00";
          case "duration" -> "P3Y6M4DT12H30M5S";
          case "byte" -> "Ynl0ZSBhcnJvdw==";
          default -> name + " string value";
        };
      }
      case "number" -> 1.1;
      case "integer" -> 1;
      case "boolean" -> true;
      default -> null;
    })).ifPresent(schema::setExample);
    return parentSchema;
  }

  public DataPropertyMapper(YamlConfig config, String name, String label, String description,
      @Nullable Object exampleValue, Set<RestrictionInfo> restrictions,
      List<String> valuesFromDataRestrictions_ranges, List<String> type) {
    this.name = name;
    this.label = label;
    this.description = description;
    this.exampleValue = exampleValue;
    this.type = type;
    this.restrictions = restrictions;
    this.valuesFromDataRestrictions_ranges = valuesFromDataRestrictions_ranges;

    // Compute array and required from restrictions
    this.array =
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesArray);
    this.isRequired = config.isEnforceRequiredness() &&
        restrictions != null && restrictions.stream().anyMatch(RestrictionInfo::impliesRequired);
  }

  public Schema<?> getSchemaByDataProperty() {
    Schema<?> schema = withExample(createSchema());
    schema.setName(this.name);
    schema.setTitle(this.label);
    return schema;
  }

  private Schema<?> createSchema() {

    if (this.type.isEmpty()) {
      return (this.array) ? this.arraySchema(new StringSchema())
          : this.nonArraySchema(new StringSchema());
    } else if (this.type.size() > 1) {
      return (this.array) ? this.composedSchema() : this.nonArraySchema(new Schema<>());
    }

    String schemaType = getDataType(this.type.getFirst());
    if (schemaType == null) {
      throw new RuntimeException("property " + this.name + " type " + this.type);
    }

    //return (this.array) ? this.arraySchema(new Schema<>()) : this.nonArraySchema(new Schema<>());
    return switch (schemaType) {
      case STRING_TYPE -> (this.array) ? this.arraySchema(new StringSchema())
          : this.nonArraySchema(new StringSchema());
      case NUMBER_TYPE -> (this.array) ? this.arraySchema(new NumberSchema())
          : this.nonArraySchema(new NumberSchema());
      case INTEGER_TYPE -> (this.array) ? this.arraySchema(new IntegerSchema())
          : this.nonArraySchema(new IntegerSchema());
      case BOOLEAN_TYPE -> (this.array) ? this.arraySchema(new BooleanSchema())
          : this.nonArraySchema(new BooleanSchema());
      case DATETIME_TYPE -> (this.array) ? this.arraySchema(new DateTimeSchema())
          : this.nonArraySchema(new DateTimeSchema());
      default -> throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
    };
  }

  /**
   * Generate a range of multiple values depending on the range axiom
   *
   * @return An ArraySchema: including a composedSchema with a list of items for anyOf, allOf restrictions.
   */
  private ArraySchema composedSchema() {
    ArraySchema array = new ArraySchema();
    Schema<?> schema;
    ComposedSchema composedSchema = new ComposedSchema();
    array.setDescription(description);

    // Operations for managing boolean combinations
    for (RestrictionInfo restriction : this.restrictions) {
      for (String item : this.type) {
        switch (getDataType(item)) {
          case STRING_TYPE:
            schema = new StringSchema();

            if (item.equals("anyURI")) {
              schema.format("uri");
            } else if (item.equals("byte")) {
              schema.format("byte");
            }

            break;
          case NUMBER_TYPE:
            schema = new NumberSchema().example(1.1);

            if (item.equals("float")) {
              schema.format("double");
            } else if (item.equals("double")) {
              schema.format("double");
            } else {
              schema.format("number");
            }

            break;
          case INTEGER_TYPE:
            schema = new IntegerSchema();
            if (item.equals("long")) {
              schema.format("int64");
            }
            break;
          case BOOLEAN_TYPE:
            schema = new BooleanSchema();
            break;
          case DATETIME_TYPE:
            schema = withExample(new DateTimeSchema());
            break;
          default:
            throw new RuntimeException("datatype mapping failed " + this.type.getFirst());
            //schema = new Schema<>();
        }
        isRequired |= restriction.impliesRequired();
        switch (restriction) {
          case UnionOf unionOf -> composedSchema.addAnyOfItem(withExample(schema));
          case IntersectionOf intersectionOf -> composedSchema.addAllOfItem(withExample(schema));
          default -> {
            // Other restriction types (DataSomeValuesFrom, etc.) don't affect composed schemas
            // They are handled in applySchemaRestrictions()
          }
        }
      }
    }

    array.setItems(composedSchema);
    return array;
  }

  private Schema<?> nonArraySchema(Schema<?> base) {
    base.setDescription(this.description);

    this.applySchemaRestrictions(base);
    return base;
  }

  private ArraySchema arraySchema(Schema<?> base) {
    ArraySchema array = new ArraySchema();
    array.setDescription(this.description);

    if (this.restrictions.stream().anyMatch(r -> r instanceof RestrictionInfo.ComplementOf)) {
      Schema<?> schema = new Schema<>();
      Schema<?> complementOf = new Schema<>();
      complementOf.setType(getDataType(this.type.getFirst()));
      complementOf.setFormat(this.type.getFirst());
      schema.setNot(complementOf);
      array.setItems(schema);
      return array;
    }

    this.applySchemaRestrictions(base);

    // Can this be done in a better way?
    Integer minItemsInteger = base.getMinItems();
    if (minItemsInteger != null) {
      base.setMinItems(null);
      array.setMinItems(minItemsInteger);
    }

    // Can this be done in a better way?
    Integer maxItemsInteger = base.getMaxItems();
    if (maxItemsInteger != null) {
      base.setMaxItems(null);
      array.setMaxItems(maxItemsInteger);
    }

    array.setItems(base);

    return array;
  }

  public String getName() {
    return name;
  }

  private void applySchemaRestrictions(Schema<?> base) {
    if (base.getType().equals("array")) {
      if (base instanceof ArraySchema arraySchema) {
        for (RestrictionInfo restriction : this.restrictions) {
          restriction.applyToArraySchema(arraySchema);
        }
      }
    } else {
      for (RestrictionInfo restriction : this.restrictions) {
        isRequired |= restriction.impliesRequired();
        switch (restriction) {
          case DataHasValue data -> base.setDefault(data.expression().getFiller().getLiteral());
          case DataOneOf _dataOneOf -> {
            if (CollectionUtils.isNotEmpty(this.valuesFromDataRestrictions_ranges)) {
              if (base instanceof StringSchema stringSchema) {
                this.valuesFromDataRestrictions_ranges.stream().sorted()
                    .forEach(stringSchema::addEnumItemObject);
              }
            }
          }
          default -> {
            // nothing to do
          }
        }
      }
    }
  }

}

